1	/** A live cell identified by its [x, y] coordinates. */
2	type Cell = [number, number];
3	
4	/** Encodes a cell as a string so it can be used as a Set/Map key. */
5	const toKey = ([x, y]: Cell): string => `${x},${y}`;
6	
7	/** Decodes a string key back into a cell. */
8	const fromKey = (key: string): Cell => {
9	  const [x, y] = key.split(",").map(Number);
10	  return [x, y];
11	};
12	
13	export function nextGeneration(cells: Cell[]): Cell[] {
14	  const living = new Set(cells.map(toKey));
15	
16	  const neighborCounts = new Map<string, number>();
17	  for (const [x, y] of cells) {
18	    for (let dx = -1; dx <= 1; dx++) {
19	      for (let dy = -1; dy <= 1; dy++) {
20	        if (dx === 0 && dy === 0) continue;
21	        const key = toKey([x + dx, y + dy]);
22	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
23	      }
24	    }
25	  }
26	
27	  const next: Cell[] = [];
28	  for (const [key, count] of neighborCounts) {
29	    const isAlive = living.has(key);
30	    if (count === 3 || (isAlive && count === 2)) {
31	      next.push(fromKey(key));
32	    }
33	  }
34	  return next;
35	}
36

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("returns an empty array for an empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("a single live cell dies (underpopulation) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("Rule 1 underpopulation: two cells each with 1 neighbor die — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 4 reproduction: a dead cell with exactly 3 live neighbors becomes alive", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
16	    expect(result).toHaveLength(4);
17	    expect(result).toEqual(
18	      expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]]),
19	    );
20	  });
21	  it("Rule 2 survival: a live cell with 2 live neighbors lives on", () => {
22	    // Three in a row: only the middle cell has 2 live neighbors and survives.
23	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
24	    expect(result).toEqual(expect.arrayContaining([[1, 0]]));
25	    expect(result).toContainEqual([1, 0]);
26	  });
27	  it.todo("Rule 3 overpopulation: a live cell with more than 3 live neighbors dies");
28	  it.todo("Block still life is unchanged — [(0,0),(1,0),(0,1),(1,1)] → same");
29	  it.todo("Blinker oscillator: vertical → horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
30	  it.todo("handles negative coordinates");
31	});
